class SamePlaceModule(dspy.Module):
    def __init__(self):
        super().__init__()
        self.classify = dspy.Predict(
            "input_name: str, input_address: str, match_name: str, match_address: str, distance: float -> is_same: bool"
        )

    def forward(self, **inputs):
        import re

        def normalize_name(s):
            s = (s or "").lower()
            # Remove common business suffixes/words
            stopwords = {
                "the", "a", "an", "inc", "incorporated", "llc", "ltd", "co",
                "corp", "corporation", "company", "restaurant", "cafe", "bar",
                "and", "&",
            }
            s = re.sub(r"[^a-z0-9\s]", " ", s)
            tokens = [t for t in s.split() if t and t not in stopwords]
            # also strip trailing digits like "U & I LIQUORS 2" -> "u i liquors"
            # but keep numeric tokens that aren't trailing
            while tokens and tokens[-1].isdigit():
                tokens.pop()
            return " ".join(tokens)

        STREET_ABBR = {
            "street": "st", "st": "st",
            "avenue": "ave", "ave": "ave", "av": "ave",
            "boulevard": "blvd", "blvd": "blvd",
            "road": "rd", "rd": "rd",
            "drive": "dr", "dr": "dr",
            "lane": "ln", "ln": "ln",
            "court": "ct", "ct": "ct",
            "place": "pl", "pl": "pl",
            "highway": "hwy", "hwy": "hwy",
            "parkway": "pkwy", "pkwy": "pkwy",
            "terrace": "ter", "ter": "ter",
            "circle": "cir", "cir": "cir",
            "square": "sq", "sq": "sq",
            "north": "n", "n": "n",
            "south": "s", "s": "s",
            "east": "e", "e": "e",
            "west": "w", "w": "w",
            "northeast": "ne", "ne": "ne",
            "northwest": "nw", "nw": "nw",
            "southeast": "se", "se": "se",
            "southwest": "sw", "sw": "sw",
        }

        def normalize_address(s):
            s = (s or "").lower()
            s = re.sub(r"[^a-z0-9\s]", " ", s)
            tokens = s.split()
            tokens = [STREET_ABBR.get(t, t) for t in tokens]
            return " ".join(tokens)

        def address_number(s):
            s = (s or "").strip()
            m = re.match(r"\s*(\d+)", s)
            return m.group(1) if m else None

        def address_street_tokens(addr_norm):
            # tokens minus the leading number
            toks = addr_norm.split()
            if toks and toks[0].isdigit():
                toks = toks[1:]
            return toks

        def jaccard(a_tokens, b_tokens):
            sa, sb = set(a_tokens), set(b_tokens)
            if not sa and not sb:
                return 1.0
            if not sa or not sb:
                return 0.0
            return len(sa & sb) / len(sa | sb)

        def char_similarity(a, b):
            # simple Dice coefficient on character bigrams
            if not a or not b:
                return 0.0
            if a == b:
                return 1.0
            def bigrams(s):
                s = s.replace(" ", "")
                return [s[i:i+2] for i in range(len(s) - 1)]
            ba, bb = bigrams(a), bigrams(b)
            if not ba or not bb:
                return 0.0
            from collections import Counter
            ca, cb = Counter(ba), Counter(bb)
            inter = sum((ca & cb).values())
            return 2 * inter / (len(ba) + len(bb))

        try:
            dist = float(inputs.get("distance", 0) or 0)
        except (TypeError, ValueError):
            dist = 0.0

        n1 = normalize_name(inputs.get("input_name", ""))
        n2 = normalize_name(inputs.get("match_name", ""))
        a1 = normalize_address(inputs.get("input_address", ""))
        a2 = normalize_address(inputs.get("match_address", ""))

        num1 = address_number(a1)
        num2 = address_number(a2)
        st1 = address_street_tokens(a1)
        st2 = address_street_tokens(a2)

        name_sim = char_similarity(n1, n2)
        name_jacc = jaccard(n1.split(), n2.split())
        street_jacc = jaccard(st1, st2)
        addr_sim = char_similarity(a1, a2)

        # Deterministic decision rules.
        # Rule 1: Very far apart -> definitely different places.
        if dist >= 150:
            return dspy.Prediction(is_same=False)

        # Rule 2: Same/very close addresses AND similar names AND close distance -> same.
        same_address = (
            a1 == a2
            or (num1 is not None and num1 == num2 and street_jacc >= 0.5)
        )
        if same_address and dist < 100 and (name_sim >= 0.6 or name_jacc >= 0.5 or n1 == n2):
            return dspy.Prediction(is_same=True)

        # Rule 3: Different street numbers and low name similarity at non-trivial distance -> different.
        if num1 and num2 and num1 != num2 and name_sim < 0.5 and dist > 30:
            return dspy.Prediction(is_same=False)

        # Rule 4: Names totally different and addresses totally different.
        if name_sim < 0.3 and addr_sim < 0.4:
            return dspy.Prediction(is_same=False)

        # Rule 5: Exact name and address match.
        if n1 == n2 and a1 == a2:
            return dspy.Prediction(is_same=True)

        # Ambiguous: fall back to LLM.
        result = self.classify(**inputs)
        val = result.is_same
        if isinstance(val, bool):
            return dspy.Prediction(is_same=val)
        if isinstance(val, str):
            return dspy.Prediction(is_same=val.strip().lower() in ("true", "1", "yes"))
        return dspy.Prediction(is_same=bool(val))
